@Controller
class SamlController {

    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping(value = "/", produces = MediaType.TEXT_HTML_VALUE)
    public void home(HttpServletRequest request, HttpServletResponse response) throws IOException {
        response.setContentType(MediaType.TEXT_HTML_VALUE);
        PrintWriter writer = response.getWriter();
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();

        writer.println("<html><body>");
        if (authentication != null && authentication.isAuthenticated() && authentication instanceof SamlAuthenticationToken) {
            SamlAuthenticationToken token = (SamlAuthenticationToken) authentication;
            writer.println("<h2>Authenticated</h2>");
            writer.println("<p>User: " + escape(token.getName()) + "</p>");
            writer.println("<h3>Attributes</h3><ul>");
            for (Map.Entry<String, List<String>> entry : token.getAttributes().entrySet()) {
                writer.println("<li>" + escape(entry.getKey()) + " = " + escape(String.join(", ", entry.getValue())) + "</li>");
            }
            writer.println("</ul>");
            writer.println("<form method='post' action='/logout'><button type='submit'>Logout</button></form>");
        } else {
            writer.println("<h2>Not Authenticated</h2>");
            writer.println("<p>POST a SAMLResponse to /saml/acs</p>");
        }
        writer.println("</body></html>");
    }

    @PostMapping("/saml/acs")
    public void assertionConsumerService(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String samlResponse = request.getParameter("SAMLResponse");
        if (!StringUtils.hasText(samlResponse)) {
            response.sendError(HttpStatus.BAD_REQUEST.value(), "Missing SAMLResponse");
            return;
        }

        try {
            SamlPrincipal principal = samlService.processSamlResponse(samlResponse, request);
            SamlAuthenticationToken authentication = new SamlAuthenticationToken(principal);

            SecurityContext context = SecurityContextHolder.createEmptyContext();
            context.setAuthentication(authentication);
            SecurityContextHolder.setContext(context);

            request.getSession(true).setAttribute("USER_ATTRIBUTES", principal.getAttributes());
            request.getSession().setAttribute("NAME_ID", principal.getNameId());
            request.getSession().setAttribute(HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY, context);

            response.sendRedirect("/");
        } catch (Exception e) {
            response.sendError(HttpStatus.UNAUTHORIZED.value(), "Invalid SAML Response");
        }
    }

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        SecurityContextHolder.clearContext();
        if (request.getSession(false) != null) {
            request.getSession(false).invalidate();
        }
        response.sendRedirect("/");
    }

    private static String escape(String value) {
        if (value == null) return "";
        return value.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;");
    }
}

@Component
class SamlService {

    private static final String SP_ENTITY_ID = "urn:example:sp";
    private static final String ACS_URL = "http://localhost:8080/saml/acs";

    private static final String IDP_CERTIFICATE_PEM =
            "-----BEGIN CERTIFICATE-----\n" +
            "MIIC8DCCAdigAwIBAgIJAKExampleReplaceThisCertData\n" +
            "-----END CERTIFICATE-----";

    public SamlPrincipal processSamlResponse(String samlResponseBase64, HttpServletRequest request) throws Exception {
        byte[] decoded = Base64.getDecoder().decode(samlResponseBase64);
        Document document = parseXml(decoded);

        validateBasicStructure(document);
        validateDestination(document);
        validateAudience(document);
        validateTimeConditions(document);
        validateStatusSuccess(document);
        validateSignaturePresence(document);

        String nameId = extractNameId(document);
        Map<String, List<String>> attributes = extractAttributes(document);
        List<String> roles = extractRoles(attributes);

        return new SamlPrincipal(nameId, attributes, roles);
    }

    private Document parseXml(byte[] xmlBytes) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
        DocumentBuilder builder = dbf.newDocumentBuilder();
        return builder.parse(new ByteArrayInputStream(xmlBytes));
    }

    private void validateBasicStructure(Document document) throws Exception {
        XPath xpath = newXPath();
        String responseLocal = xpath.evaluate("local-name(/*)", document);
        if (!"Response".equals(responseLocal)) {
            throw new SecurityException("Not a SAML Response");
        }
    }

    private void validateStatusSuccess(Document document) throws Exception {
        XPath xpath = newXPath();
        String statusCode = (String) xpath.evaluate(
                "/*[local-name()='Response']/*[local-name()='Status']/*[local-name()='StatusCode']/@Value",
                document,
                XPathConstants.STRING
        );
        if (!"urn:oasis:names:tc:SAML:2.0:status:Success".equals(statusCode)) {
            throw new SecurityException("SAML status not success");
        }
    }

    private void validateDestination(Document document) throws Exception {
        XPath xpath = newXPath();
        String destination = (String) xpath.evaluate(
                "/*[local-name()='Response']/@Destination",
                document,
                XPathConstants.STRING
        );
        if (StringUtils.hasText(destination) && !ACS_URL.equals(destination)) {
            throw new SecurityException("Invalid destination");
        }
    }

    private void validateAudience(Document document) throws Exception {
        XPath xpath = newXPath();
        NodeList audiences = (NodeList) xpath.evaluate(
                "//*[local-name()='AudienceRestriction']/*[local-name()='Audience']",
                document,
                XPathConstants.NODESET
        );
        boolean match = false;
        for (int i = 0; i < audiences.getLength(); i++) {
            String audience = audiences.item(i).getTextContent();
            if (SP_ENTITY_ID.equals(audience != null ? audience.trim() : null)) {
                match = true;
                break;
            }
        }
        if (!match) {
            throw new SecurityException("Invalid audience");
        }
    }

    private void validateTimeConditions(Document document) throws Exception {
        XPath xpath = newXPath();
        String notBefore = (String) xpath.evaluate(
                "//*[local-name()='Conditions']/@NotBefore",
                document,
                XPathConstants.STRING
        );
        String notOnOrAfter = (String) xpath.evaluate(
                "//*[local-name()='Conditions']/@NotOnOrAfter",
                document,
                XPathConstants.STRING
        );

        Instant now = Instant.now();
        if (StringUtils.hasText(notBefore) && now.isBefore(Instant.parse(notBefore).minusSeconds(60))) {
            throw new SecurityException("Assertion not yet valid");
        }
        if (StringUtils.hasText(notOnOrAfter) && !now.isBefore(Instant.parse(notOnOrAfter).plusSeconds(60))) {
            throw new SecurityException("Assertion expired");
        }
    }

    private void validateSignaturePresence(Document document) throws Exception {
        XPath xpath = newXPath();
        Node signature = (Node) xpath.evaluate(
                "/*[local-name()='Response']/*[local-name()='Signature'] | " +
                        "/*[local-name()='Response']/*[local-name()='Assertion']/*[local-name()='Signature']",
                document,
                XPathConstants.NODE
        );
        if (signature == null) {
            throw new SecurityException("Missing signature");
        }
    }

    private String extractNameId(Document document) throws Exception {
        XPath xpath = newXPath();
        String nameId = (String) xpath.evaluate(
                "//*[local-name()='Subject']/*[local-name()='NameID']/text()",
                document,
                XPathConstants.STRING
        );
        if (!StringUtils.hasText(nameId)) {
            throw new SecurityException("Missing NameID");
        }
        return nameId.trim();
    }

    private Map<String, List<String>> extractAttributes(Document document) throws Exception {
        XPath xpath = newXPath();
        NodeList attributeNodes = (NodeList) xpath.evaluate(
                "//*[local-name()='AttributeStatement']/*[local-name()='Attribute']",
                document,
                XPathConstants.NODESET
        );

        Map<String, List<String>> attributes = new LinkedHashMap<>();
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Node attribute = attributeNodes.item(i);
            Node nameNode = attribute.getAttributes() != null ? attribute.getAttributes().getNamedItem("Name") : null;
            if (nameNode == null) {
                continue;
            }
            String name = nameNode.getNodeValue();
            List<String> values = new ArrayList<>();
            NodeList children = attribute.getChildNodes();
            for (int j = 0; j < children.getLength(); j++) {
                Node child = children.item(j);
                if ("AttributeValue".equals(child.getLocalName())) {
                    String value = child.getTextContent();
                    if (value != null) {
                        values.add(value.trim());
                    }
                }
            }
            attributes.put(name, values);
        }
        return attributes;
    }

    private List<String> extractRoles(Map<String, List<String>> attributes) {
        List<String> roles = new ArrayList<>();
        List<String> candidateKeys = Arrays.asList("Role", "Roles", "groups", "Group", "memberOf");
        for (String key : candidateKeys) {
            if (attributes.containsKey(key)) {
                roles.addAll(attributes.get(key));
            }
        }
        if (roles.isEmpty()) {
            roles.add("USER");
        }
        return roles.stream()
                .filter(StringUtils::hasText)
                .map(String::trim)
                .map(v -> v.startsWith("ROLE_") ? v : "ROLE_" + v.toUpperCase(Locale.ROOT).replaceAll("[^A-Z0-9_]", "_"))
                .distinct()
                .collect(Collectors.toList());
    }

    private XPath newXPath() {
        XPath xpath = XPathFactory.newInstance().newXPath();
        xpath.setNamespaceContext(new UniversalNamespaceContext());
        return xpath;
    }

    @SuppressWarnings("unused")
    private X509Certificate loadCertificate() throws Exception {
        String pem = IDP_CERTIFICATE_PEM
                .replace("-----BEGIN CERTIFICATE-----", "")
                .replace("-----END CERTIFICATE-----", "")
                .replaceAll("\\s+", "");
        byte[] der = Base64.getDecoder().decode(pem);
        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        return (X509Certificate) cf.generateCertificate(new ByteArrayInputStream(der));
    }

    @SuppressWarnings("unused")
    private PublicKey loadPublicKeyFromCertificate() throws Exception {
        return loadCertificate().getPublicKey();
    }

    @SuppressWarnings("unused")
    private byte[] inflate(byte[] data) throws IOException {
        try (InflaterInputStream in = new InflaterInputStream(new ByteArrayInputStream(data), new Inflater(true))) {
            return in.readAllBytes();
        }
    }
}

class SamlPrincipal {
    private final String nameId;
    private final Map<String, List<String>> attributes;
    private final List<String> roles;

    SamlPrincipal(String nameId, Map<String, List<String>> attributes, List<String> roles) {
        this.nameId = nameId;
        this.attributes = Collections.unmodifiableMap(new LinkedHashMap<>(attributes));
        this.roles = Collections.unmodifiableList(new ArrayList<>(roles));
    }

    public String getNameId() {
        return nameId;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }

    public List<String> getRoles() {
        return roles;
    }
}

class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final SamlPrincipal principal;

    SamlAuthenticationToken(SamlPrincipal principal) {
        super(principal.getRoles().stream().map(SimpleGrantedAuthority::new).collect(Collectors.toList()));
        this.principal = principal;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return "";
    }

    @Override
    public SamlPrincipal getPrincipal() {
        return principal;
    }

    @Override
    public String getName() {
        return principal.getNameId();
    }

    public Map<String, List<String>> getAttributes() {
        return principal.getAttributes();
    }
}

@Component
class SamlSessionFilter extends OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {
        if (SecurityContextHolder.getContext().getAuthentication() == null && request.getSession(false) != null) {
            Object ctx = request.getSession(false).getAttribute(HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY);
            if (ctx instanceof SecurityContext) {
                SecurityContextHolder.setContext((SecurityContext) ctx);
            }
        }
        try {
            filterChain.doFilter(request, response);
        } finally {
            SecurityContextHolder.clearContext();
        }
    }
}

class UniversalNamespaceContext implements NamespaceContext {

    @Override
    public String getNamespaceURI(String prefix) {
        if ("samlp".equals(prefix)) {
            return "urn:oasis:names:tc:SAML:2.0:protocol";
        }
        if ("saml".equals(prefix)) {
            return "urn:oasis:names:tc:SAML:2.0:assertion";
        }
        if ("ds".equals(prefix)) {
            return "http://www.w3.org/2000/09/xmldsig#";
        }
        return XMLConstants.NULL_NS_URI;
    }

    @Override
    public String getPrefix(String namespaceURI) {
        return null;
    }

    @Override
    public Iterator<String> getPrefixes(String namespaceURI) {
        return Collections.emptyIterator();
    }
}